using Microsoft.Extensions.Logging;
using Zea.Application.Repositories.Queries;
using Zea.Application.Services;
using Zea.Domain.Verification;
using Zea.Kernel.Results;

namespace Zea.Application.Clients.Commands.Onboarding.GenerateOtp;

/// <summary>
/// Handler for generating OTP code for email or phone verification.
/// Creates verification code and raises domain events for notifications (handled asynchronously).
/// Both email and phone notifications are now event-driven via OutboxProcessor.
/// Wolverine convention: public class with Handle method matching command type.
/// </summary>
public sealed class GenerateOtpHandler(
    IUserRepositoryQuery userRepositoryQuery,
    IVerificationCodeService verificationCodeService,
    ILogger<GenerateOtpHandler> logger)
{
    private const int OtpExpirationMinutes = 15;
    private const int MaxAttempts = 3;

    public async Task<Result<GenerateOtpResponse>> Handle(GenerateOtpCommand command, CancellationToken ct)
    {
        ArgumentNullException.ThrowIfNull(command);
        var userAdminId = await userRepositoryQuery.GetAdminIdAsync(ct).ConfigureAwait(false);

        // Generate single verification code based on purpose
        var result = await verificationCodeService.GenerateCodeAsync(
                userId: userAdminId,
                purpose: command.Purpose,
                contactInfo: command.ContactInfo,
                expirationMinutes: OtpExpirationMinutes,
                maxAttempts: MaxAttempts,
                ct: ct)
            .ConfigureAwait(false);

        if (result.IsFailure)
        {
            return Result.Failure<GenerateOtpResponse>(result.Error);
        }

        var verificationCode = result.GetValue;

        // Send OTP based on purpose
        var sent = SendNotification(command, verificationCode);
        var response = new GenerateOtpResponse(sent.IsSuccess, verificationCode.ExpiresAt);

        return Result.Success(response);
    }

    private Result SendNotification(GenerateOtpCommand command, VerificationCode verificationCode)
    {
        var purpose = command.Purpose;
        switch (purpose)
        {
            case VerificationPurpose.EmailVerification:
                logger.LogEmailOtpGenerated(verificationCode.Code, command.ContactInfo);

                // Raise domain event for async email processing
                verificationCode.RequestNotification(command.ContactInfo, isEmail: true);

                return Result.Success();

            case VerificationPurpose.PhoneVerification:
                logger.LogPhoneOtpGenerated(
                    verificationCode.Code,
                    command.ContactInfo,
                    command.SendViaWhatsApp ? "WhatsApp" : "SMS");

                // Raise domain event for async phone processing
                verificationCode.RequestNotification(command.ContactInfo, isEmail: false, viaWhatsApp: command.SendViaWhatsApp);

                return Result.Success();

            default:
                return Result.Failure(ErrorResult.Validation($"Unsupported verification purpose: {purpose}"));
        }
    }
}

internal static partial class GenerateOtpHandlerLoggerDefinition
{
    [LoggerMessage(
        LogLevel.Information,
        EventId = 573,
        EventName = "EmailOtpGenerated",
        Message = "OTP code generated - Email: {Code} to {Email}")]
    public static partial void LogEmailOtpGenerated(this ILogger logger, string code, string email);

    [LoggerMessage(
        LogLevel.Information,
        EventId = 574,
        EventName = "PhoneOtpGenerated",
        Message = "OTP code generated - Phone: {Code} to {Phone} via {Channel}")]
    public static partial void LogPhoneOtpGenerated(this ILogger logger, string code, string phone, string channel);
}

using Zea.Domain.Verification;

namespace Zea.Application.Clients.Commands.Onboarding.GenerateOtp;

/// <summary>
/// Command to generate OTP verification code.
/// Pure CQRS command - validation is handled at the API layer.
/// </summary>
/// <param name="Purpose">The purpose of verification (Email or Phone)</param>
/// <param name="ContactInfo">Email address or phone number to send OTP to</param>
/// <param name="SendViaWhatsApp">If true, sends OTP via WhatsApp; if false, sends via SMS (only for phone verification)</param>
public sealed record GenerateOtpCommand(VerificationPurpose Purpose, string ContactInfo, bool SendViaWhatsApp);

namespace Zea.Application.Clients.Commands.Onboarding.GenerateOtp;

/// <summary>
/// Response for OTP generation.
/// Indicates whether the code was successfully sent.
/// </summary>
/// <param name="Sent">Whether OTP was successfully sent to the contact info</param>
/// <param name="ExpiresAt">UTC timestamp when the OTP code expires</param>
public sealed record GenerateOtpResponse(bool Sent, DateTime ExpiresAt);

