    {
        var todoItem = await _context.TodoItem.FirstOrDefaultAsync(x =>
            x.Id == id && x.TodoListId == tlid
        );

        if (todoItem == null)
        {
            return NotFound();
        }

        todoItem.Name = payload.Name;
        todoItem.IsComplete = payload.IsComplete;
        await _context.SaveChangesAsync();

        return Ok(todoItem);
    }

