        var todoItem = await _context.TodoItem.FirstOrDefaultAsync(x =>
            x.Id == id && x.TodoListId == tlid
        );

        if (todoItem == null)
        {
            return NotFound();
        }

        _context.TodoItem.Remove(todoItem);
        await _context.SaveChangesAsync();

        return NoContent();
    }
