34	/// <summary>
35	/// Base class for command (write) repositories.
36	/// Allows tracking for write operations.
37	/// </summary>
38	public abstract class RepositoryCommand<TEntity>(TodoContext context) : IRepositoryCommand<TEntity> where TEntity : Entity
39	{
40	    protected DbSet<TEntity> DbSetEntities => context.Set<TEntity>();
41	
42	    protected TodoContext Context => context;
43	
44	    public async Task<TEntity?> GetByIdAsync(Guid id, bool tracking = true, CancellationToken ct = default)
45	    {
46	        var result = !tracking
47	            ? await DbSetEntities.AsNoTracking().FirstOrDefaultAsync(x => x.Id == id, ct).ConfigureAwait(false)
48	            : await DbSetEntities.FirstOrDefaultAsync(x => x.Id == id, ct).ConfigureAwait(false);
49	
50	        return result;
51	    }
52	
53	    public async Task<TEntity?> GetByAsync(
54	        Expression<Func<TEntity, bool>> predicate,
55	        bool tracking = true,
56	        CancellationToken ct = default)
57	    {
58	        var e = DbSetEntities.Where(predicate);
59	        if (!tracking)
60	        {
61	            e = e.AsNoTracking();
62	        }
63	
64	        return await e.FirstOrDefaultAsync(ct).ConfigureAwait(false);
65	    }
66	
67	    public async Task<List<TEntity>> GetManyAsync(
68	        Expression<Func<TEntity, bool>> predicate,
69	        bool tracking = true,
70	        CancellationToken ct = default)
71	    {
72	        var query = DbSetEntities.Where(predicate);
73	        if (!tracking)
74	        {
75	            query = query.AsNoTracking();
76	        }
77	
78	        return await query.ToListAsync(ct).ConfigureAwait(false);
79	    }
80	
81	    public IQueryable<TEntity> GetQueryable(bool tracking = true, CancellationToken ct = default)
82	    {
83	        var q = DbSetEntities.AsQueryable();
84	        if (!tracking)
85	        {
86	            q = q.AsNoTracking();
87	        }
88	
89	        return q;
90	    }
91	
92	    public async Task<bool> AnyAsync(Expression<Func<TEntity, bool>> predicate, CancellationToken ct = default)
93	    {
94	        return await DbSetEntities.AsNoTracking().AnyAsync(predicate, ct).ConfigureAwait(false);
95	    }
96	
97	    public async Task<TEntity> AddAsync(TEntity entity, CancellationToken ct = default)
98	    {
99	        var e = await DbSetEntities.AddAsync(entity, ct).ConfigureAwait(false);
100	        return e.Entity;
101	    }
102	
103	    public TEntity Remove(TEntity entity)
104	    {
105	        var r = DbSetEntities.Remove(entity);
106	        return r.Entity;
107	    }
108	
109	    public TEntity Update(TEntity entity)
110	    {
111	        var e = DbSetEntities.Update(entity);
112	        return e.Entity;
113	    }
114	
115	    public async Task<int> UpdateSaveChangesAsync(TEntity entity, CancellationToken ct = default)
116	    {
117	        Update(entity);
118	
119	        return await Context.SaveChangesAsync(ct).ConfigureAwait(false);
