using FluentValidation;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using TodoApi.Application.Commands.CreateTodoList;
using TodoApi.Data;
using TodoApi.Data.Entities;
using TodoApi.Dtos;
using TodoApi.Infrastructure;
using TodoApi.Infrastructure.Extensions;
using Wolverine;

namespace TodoApi.Controllers.TodoLists
{
    [Route("api/todolists")]
    [ApiController]
    public class TodoListsController : ControllerBase
    {
        private readonly TodoContext _context;
        private readonly IMessageBus _bus;
        private readonly IValidator<CreateTodoListRequest> _createValidator;

        public TodoListsController(
            TodoContext context,
            IMessageBus bus,
            IValidator<CreateTodoListRequest> createValidator)
        {
            _context = context;
            _bus = bus;
            _createValidator = createValidator;
        }

        // GET: api/todolists
        [HttpGet]
        public async Task<ActionResult<IList<TodoList>>> GetTodoLists()
        {
            return Ok(await _context.TodoList.Include(x => x.Items).ToListAsync());
        }

        // GET: api/todolists/5
        [HttpGet("{id}")]
        public async Task<ActionResult<TodoList>> GetTodoList(long id)
        {
            var todoList = await _context.TodoList.Include(x => x.Items).FirstOrDefaultAsync(x => x.Id == id);

            if (todoList == null)
            {
                return NotFound();
            }

            return Ok(todoList);
        }

        // PUT: api/todolists/5
        // To protect from over-posting attacks, see https://go.microsoft.com/fwlink/?linkid=2123754
        [HttpPut("{id}")]
        public async Task<ActionResult> PutTodoList(long id, UpdateTodoList payload)
        {
            var todoList = await _context.TodoList.FindAsync(id);

            if (todoList == null)
            {
                return NotFound();
            }

            todoList.Name = payload.Name;
            await _context.SaveChangesAsync();

            return Ok(todoList);
        }

        // POST: api/todolists
        // To protect from over-posting attacks, see https://go.microsoft.com/fwlink/?linkid=2123754
        [HttpPost]
        public async Task<IResult> PostTodoList(CreateTodoListRequest payload, CancellationToken ct)
        {
            var validation = await _createValidator.ValidateAsync(payload, ct).ConfigureAwait(false);
            if (!validation.IsValid)
            {
                return Results.ValidationProblem(validation.ToDictionary());
            }

            var command = new CreateTodoListCommand(payload.Name);
            var result = await _bus.InvokeAsync<Result<CreateTodoListResponse>>(command, ct).ConfigureAwait(false);

            return result.Match(
                onSuccess: value => Results.Created(
                    Url.Action(nameof(GetTodoList), new { id = value.Id }) ?? string.Empty,
                    value));
        }

        // DELETE: api/todolists/5
        [HttpDelete("{id}")]
        public async Task<ActionResult> DeleteTodoList(long id)
        {
            var todoList = await _context.TodoList.FindAsync(id);
            if (todoList == null)
            {
                return NotFound();
            }

            _context.TodoList.Remove(todoList);
            await _context.SaveChangesAsync();

            return NoContent();
        }
    }
}

