using Wolverine;

namespace TodoApi.Controllers.TodoLists
{
    [Route("api/todolists")]
    [ApiController]
    public class TodoListsController(
        TodoContext context,
        IMessageBus bus,
        IValidator<CreateTodoListRequest> createValidator) : ControllerBase
    {
        // GET: api/todolists
        [HttpGet]
        public async Task<IResult> GetTodoLists(CancellationToken ct)
        {
            var query = new GetTodoListsQuery();
            var result = await bus.InvokeAsync<Result<GetTodoListsResponse>>(query, ct).ConfigureAwait(false);

            return result.ToOk(r => r.TodoLists);
        }

        // GET: api/todolists/5
        [HttpGet("{id}")]
        public async Task<ActionResult<TodoList>> GetTodoList(long id)
        {
            var todoList = await context.TodoList.Include(x => x.Items).FirstOrDefaultAsync(x => x.Id == id);

            if (todoList == null)
            {
                return NotFound();
            }

            return Ok(todoList);
        }

        // PUT: api/todolists/5
        // To protect from over-posting attacks, see https://go.microsoft.com/fwlink/?linkid=2123754
        [HttpPut("{id}")]
        public async Task<ActionResult> PutTodoList(long id, UpdateTodoList payload)
        {
            var todoList = await context.TodoList.FindAsync(id);

            if (todoList == null)
            {
                return NotFound();
            }

            todoList.Name = payload.Name;
            await context.SaveChangesAsync();

            return Ok(todoList);
        }

        // POST: api/todolists
        // To protect from over-posting attacks, see https://go.microsoft.com/fwlink/?linkid=2123754
        [HttpPost]
        public async Task<IResult> PostTodoList(CreateTodoListRequest payload, CancellationToken ct)
        {
            var validation = await createValidator.ValidateAsync(payload, ct).ConfigureAwait(false);
            if (!validation.IsValid)
            {
                return Results.ValidationProblem(validation.ToDictionary());
            }

            var command = new CreateTodoListCommand(payload.Name);
            var result = await bus.InvokeAsync<Result<CreateTodoListResponse>>(command, ct).ConfigureAwait(false);

            return result.ToCreated(
                value => Url.Action(nameof(GetTodoList), new { id = value.Id }) ?? string.Empty);
        }

        // DELETE: api/todolists/5
        [HttpDelete("{id}")]
        public async Task<ActionResult> DeleteTodoList(long id)
        {
            var todoList = await context.TodoList.FindAsync(id);
            if (todoList == null)
            {
                return NotFound();
            }

            context.TodoList.Remove(todoList);
            await context.SaveChangesAsync();

            return NoContent();
        }
    }
}

