using TodoApi.Infrastructure.Persistence;

namespace TodoApi.Data.Entities;

public class TodoList : Entity, IAuditable, ISynchronizable
{
    private TodoList()
    {
        Name = string.Empty;
        CreatedAt = DateTime.UtcNow;
    }

    public TodoList(string name, DateTime createdAt)
    {
        Name = name;
        CreatedAt = createdAt;
    }

    public string Name { get; private set; }

    public ICollection<TodoItem> Items { get; } = [];

    public DateTime CreatedAt { get; }

    public DateTime? UpdatedAt { get; private set; }

    public bool IsSynchronized { get; private set; }

    public DateTime? SynchronizedAt { get; private set; }

    public void Rename(string name, DateTime updatedAt)
    {
        Name = name;
        UpdatedAt = updatedAt;
    }

    public void AddItem(TodoItem item, DateTime updatedAt)
    {
        Items.Add(item);
        UpdatedAt = updatedAt;
    }

    public void RemoveItem(TodoItem item, DateTime upDateTime)
    {
        Items.Remove(item);
        UpdatedAt = upDateTime;
    }

    public void Synchronized(DateTime synchronizedAt)
    {
        IsSynchronized = true;
        SynchronizedAt = synchronizedAt;
    }
}

using Microsoft.Extensions.Logging;
using TodoApi.Data.Entities;
using TodoApi.Infrastructure;
using TodoApi.Infrastructure.Persistence;

namespace TodoApi.Application.Commands.UpdateTodoList;

public sealed class UpdateTodoListHandler(
    IRepositoryCommand<TodoList> repository,
    IClock clock,
    ILogger<UpdateTodoListHandler> logger)
{
    public async Task<Result<UpdateTodoListResponse>> Handle(UpdateTodoListCommand command, CancellationToken ct)
    {
        ArgumentNullException.ThrowIfNull(command);

        var todoList = await repository.GetByIdAsync(command.Id, ct: ct).ConfigureAwait(false);
        if (todoList is null)
        {
            return Result.Failure<UpdateTodoListResponse>(
                ErrorResult.NotFound(nameof(TodoList), command.Id.ToString()));
        }

        todoList.Rename(command.Name, clock.UtcNow);

        logger.LogTodoListUpdated(todoList.Id, todoList.Name);

        return Result.Success(new UpdateTodoListResponse(todoList.Id, todoList.Name, todoList.UpdatedAt));
    }
}

internal static partial class UpdateTodoListHandlerLoggerDefinition
{
    [LoggerMessage(
        EventId = 400,
        Level = LogLevel.Information,
        EventName = "TodoListUpdated",
        Message = "TodoList updated - Id: {Id}, Name: {Name}")]
    public static partial void LogTodoListUpdated(this ILogger logger, Guid id, string name);
}

