6	/// Wolverine middleware that manages database transactions for commands.
7	/// Applied only to Commands via policy configuration (not queries).
8	/// Automatically saves changes after successful command execution.
9	/// Implements the Unit of Work pattern for transactional consistency.
10	/// </summary>
11	public sealed class TransactionMiddleware
12	{
13	    /// <summary>
14	    /// Always executed after the handler completes (successfully or with exception).
15	    /// Saves changes only if there are tracked changes in the DbContext.
16	    /// This ensures commands are transactional without explicit SaveChanges calls.
17	    /// IUnitOfWork is injected by Wolverine's code generation.
18	    /// </summary>
19	    public async Task Finally(TodoContext dbContext, CancellationToken cancellationToken)
20	    {
21	        ArgumentNullException.ThrowIfNull(dbContext);
22	
23	        // Only save if there are actual changes
24	        // This prevents unnecessary database calls for read-only operations
25	        if (!dbContext.ChangeTracker.HasChanges())
26	        {
27	            return;
28	        }
29	
30	        await dbContext.SaveChangesAsync(cancellationToken).ConfigureAwait(false);
31	    }
