using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging.Abstractions;
using TodoApi.Application.Commands.CreateTodoList;
using TodoApi.Data;
using TodoApi.Data.Entities;
using TodoApi.Infrastructure;
using TodoApi.Infrastructure.Persistence;

namespace TodoApi.Tests.Application.Commands.CreateTodoList;

public sealed class CreateTodoListHandlerTests
{
    [Fact]
    public async Task Handle_WhenCalled_PersistsTodoListAndReturnsResponse()
    {
        var createdAt = new DateTime(2026, 4, 20, 12, 0, 0, DateTimeKind.Utc);
        await using var context = new TodoContext(
            new DbContextOptionsBuilder<TodoContext>()
                .UseInMemoryDatabase(Guid.NewGuid().ToString())
                .Options);
        var repository = new TodoListRepositoryCommand(context);
        var clock = new FixedClock(createdAt);
        var handler = new CreateTodoListHandler(
            repository,
            clock,
            NullLogger<CreateTodoListHandler>.Instance);

        var result = await handler.Handle(new CreateTodoListCommand("Task 1"), CancellationToken.None);
        await context.SaveChangesAsync();

        Assert.True(result.IsSuccess);
        Assert.Equal("Task 1", result.GetValue.Name);
        Assert.Equal(createdAt, result.GetValue.CreatedAt);
        Assert.NotEqual(Guid.Empty, result.GetValue.Id);

        var persisted = await context.TodoList.FirstAsync();
        Assert.Equal(result.GetValue.Id, persisted.Id);
        Assert.Equal("Task 1", persisted.Name);
        Assert.Equal(createdAt, persisted.CreatedAt);
    }

    private sealed class FixedClock(DateTime utcNow) : IClock
    {
        public DateTime UtcNow { get; } = utcNow;
    }

    private sealed class TodoListRepositoryCommand(TodoContext context)
        : RepositoryCommand<TodoList>(context);
}

