        Guid id,
        Expression<Func<TodoList, T>> projection,
        CancellationToken ct = default)
        => await context.TodoList
            .Where(x => x.Id == id)
            .Select(projection)
            .FirstOrDefaultAsync(ct)
            .ConfigureAwait(false);

